import { useState } from 'react'
import TicketCard from './TicketCard'
import { DragDropProvider, Droppable } from './Drag&Drop'

function groupBy(arr, key) {
    const dict = new Map()
    arr.forEach((item) => {
        dict.set(item[key], [...(dict.get(item[key]) || []), item])
    })
    return dict
}

function StatusColumn({ id, title, content, onDrop }) {
    return (
        <Droppable id={id} onDrop={onDrop}>
            <div className='border rounded-md border-gray-600 min-h-full bg-gray-300 p-4'>
                <div className='ahqt ahri ahrt ahsb ahsp ahsv ahtd ahtf ahtj ahud ahuk'>
                    {title}
                </div>
                <div className='flex flex-col gap-y-4'>
                    {content}
                </div>
            </div>
        </Droppable>
    )
}

export default function StatusColumns({ cards }) {
    const [tickets, setTickets] = useState(cards)

    function handleDragEnd(columnName, event) {
        if (event.canceled) return
        const { source } = event.operation
        if (!source) return
        setTickets(prev =>
            prev.map(ticket =>
                ticket.id === source.id
                    ? { ...ticket, ticketStatus: columnName }
                    : ticket
            )
        )
    }

    const columns = groupBy(tickets, 'ticketStatus')

    return (
        <DragDropProvider>
            <div className='min-w-full flex flex-row gap-x-8 justify-center'>
                {[...columns.keys()].map(columnName => (
                    <StatusColumn
                        key={columnName}
                        id={columnName}
                        title={<span>{columnName}</span>}
                        onDrop={(event) => handleDragEnd(columnName, event)}
                        content={columns.get(columnName).map(tkt => (
                            <TicketCard
                                key={tkt.id}
                                id={tkt.id}
                                title={tkt.title}
                                storyPoints={tkt.storyPoints}
                                profilePicUrl={tkt.assignee.avatar}
                                type={'STORY'}
                            />
                        ))}
                    />
                ))}
            </div>
        </DragDropProvider>
    )
}
